        + '<div class="ec-lane-header">'
        + '<span class="ec-lane-label" style="color:' + col + ';">' + T.esc(label) + '</span>'
        + '<span class="ec-lane-source">' + T.esc(source) + '</span>'
        + (badgeText ? T.laneBadge(badgeText, col) : '')
